package be.schaubroeck.lpb.rkm.rekenmotor.results;

import be.schaubroeck.lpb.rkm.rekenmotor.RekenContext;
import be.schaubroeck.lpb.rkm.rekenmotor.RekenTijd;
import be.schaubroeck.lpb.rkm.rekenmotor.TussenkomstManager;
import be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey;
import be.schaubroeck.lpb.rkm.rekenmotor.mapkeys.RekenHoofdKey;
import be.schaubroeck.lpb.rkm.rekenmotor.service.ControlesRekenResultatenService;
import be.schaubroeck.lpb.rkm.rekenmotor.util.RekenFeedback;
import be.schaubroeck.lpb.tools.Admin;
import be.schaubroeck.lpb.tools.ManueleTussenkomst;
import be.schaubroeck.lpb.tools.Persoon;
import be.schaubroeck.lpb.tools.RekenHoofd;
import be.schaubroeck.lpb.tools.RekenOverdracht;
import be.schaubroeck.lpb.tools.SleutelTussenkomstHoofd;
import be.schaubroeck.lpb.tools.service.ControleAgendaService;
import be.schaubroeck.lpb.tools.service.MaandTotaalService;
import be.schaubroeck.lpb.tools.service.ManueleTussenkomstService;
import be.schaubroeck.lpb.tools.service.RegulAgendaService;
import be.schaubroeck.lpb.tools.service.RekenResultatenService;
import be.schaubroeck.lpb.tools.service.SleutelTussenkomstService;
import be.schaubroeck.lpb.tools.service.WachtAgendaService;
import be.schaubroeck.temporal.util.TemporalContext;
import com.google.common.collect.HashMultimap;
import com.google.common.collect.Multimap;
import com.google.common.collect.Ordering;
import com.google.common.collect.SortedSetMultimap;
import com.google.common.collect.TreeMultimap;

import java.util.ArrayList;
import java.util.Collection;
import java.util.Comparator;
import java.util.List;
import java.util.SortedSet;

import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.PERSOON_KEY;
import static be.schaubroeck.lpb.rkm.rekenmotor.keys.RekenChainKey.REKENTIJD_KEY;

public class NeutraliseerResultaatHandlerImp extends ResultaatHandlerImp {

    private boolean persisteerRekenResultaten = true;

    private ManueleTussenkomstService manueleTussenkomstService;
    private SleutelTussenkomstService sleutelTussenkomstService;
    private MaandTotaalVormer vormer;

    public NeutraliseerResultaatHandlerImp(
            RekenResultatenService rekenResultatenService, WachtAgendaService wachtAgendaService,
            ControleAgendaService controleAgendaService, ControlesRekenResultatenService controlesRekenResultatenService,
            ManueleTussenkomstService manueleTussenkomstService, RegulAgendaService regulAgendaService,
            SleutelTussenkomstService sleutelTussenkomstService, MaandTotaalService maandTotaalService) {
        super(rekenResultatenService, wachtAgendaService, regulAgendaService, controleAgendaService, controlesRekenResultatenService);
        this.manueleTussenkomstService = manueleTussenkomstService;
        this.sleutelTussenkomstService = sleutelTussenkomstService;
        this.vormer = new MaandTotaalVormer(maandTotaalService);
    }

    @Override
    public void verwerkResultaten(Admin admin, RekenContext mainContext) {
        if (persisteerRekenResultaten) {
            super.verwerkResultaten(admin, mainContext);
        }
        RekenTijd rekenTijd = mainContext.getUnchecked(RekenChainKey.REKENTIJD_KEY);
        TemporalContext temporalContext = TemporalContext.getInstance();
        TussenkomstManager tussenkomstManager = mainContext.getUnchecked(RekenChainKey.TUSSENKOMST_MANAGER_KEY);
        Collection<ManueleTussenkomst> tussenkomsten = tussenkomstManager.getPersoonsElementen();
        temporalContext.setWerkTijdstip(rekenTijd.rekenTijdstip);
        for (ManueleTussenkomst tussenkomst : tussenkomsten) {
            if (tussenkomst.getId() == null) {
                manueleTussenkomstService.create(admin, tussenkomst);
            }
        }
        Collection<SleutelTussenkomstHoofd> sleutelTussenkomsten = tussenkomstManager.getSleutelTussenkomsten();
        for (SleutelTussenkomstHoofd sleutelTussenkomst : sleutelTussenkomsten) {
            if (sleutelTussenkomst.getId() == null) {
                sleutelTussenkomstService.create(admin, sleutelTussenkomst);
            }
        }

        temporalContext.clearWerkTijdstip();
    }

    protected boolean opslaanNulResultaten(RekenContext mainContext) {
        return false;
    }

    protected void persisteerRekenResultaten(Admin admin, List<RekenHoofd> outputs, List<RekenHoofd> bestaanden, RekenFeedback feedback) {
        boolean heeftBedragen =
                outputs.stream().flatMap(t -> t.getRekenLijnen().stream()).map(t -> !t.getRekenBedragen().isEmpty()).findAny().isPresent();
        Multimap<RekenHoofdKey, RekenOverdracht> rekenOverdrachtMap = HashMultimap.create();
        outputs.forEach(t -> rekenOverdrachtMap.putAll(new RekenHoofdKey(t), t.getRekenOverdrachten()));

        if (!rekenOverdrachtMap.isEmpty() && !heeftBedragen) {
            SortedSetMultimap<RekenHoofdKey, RekenHoofd> bestaandenMap =
                    TreeMultimap.create(Ordering.natural(), Comparator.comparing(RekenHoofd::getRekenTijdstip).thenComparing(RekenHoofd::getId));
            bestaanden.stream().filter(t -> t.getId() != null && t.getRnummer() != null).forEach(t -> bestaandenMap.put(new RekenHoofdKey(t), t));
            List<RekenOverdracht> tePersisteren = new ArrayList<>();
            for (RekenHoofdKey key : rekenOverdrachtMap.keySet()) {
                Collection<RekenOverdracht> overdrachten = rekenOverdrachtMap.get(key);
                SortedSet<RekenHoofd> hoofden = bestaandenMap.get(key);
                if (!hoofden.isEmpty()) {
                    RekenHoofd recenste = hoofden.last();
                    for (RekenOverdracht overdracht : overdrachten) {
                        overdracht.setRekenHoofd(recenste);
                        tePersisteren.add(overdracht);
                    }
                }
            }
            rekenResultatenService.createRekenOverdrachten(admin, tePersisteren);
        } else {
            super.persisteerRekenResultaten(admin, outputs, bestaanden, feedback);
        }
    }

    @Override
    public void verwerkReguls(Admin admin, RekenContext mainContext, boolean stopState) {
        super.verwerkReguls(admin, mainContext, stopState);
    }

    public void setPersisteerRekenResultaten(boolean persisteerRekenResultaten) {
        this.persisteerRekenResultaten = persisteerRekenResultaten;
    }

    @Override
    public void cleanResultaten(Admin admin, RekenContext mainContext) {
        super.cleanResultaten(admin, mainContext);
        RekenTijd rekenTijd = mainContext.getUnchecked(REKENTIJD_KEY);
        Persoon persoon = mainContext.getUnchecked(PERSOON_KEY);
        vormer.cleanMaandtotalen(admin, rekenTijd, persoon);
    }
}
